const fs = require('fs');
const jwt = require('jsonwebtoken');
const { Client } = require('magicbell-js/user-client');

async function main() {
  try {
    const runId = process.env.ZEALT_RUN_ID || 'local';
    const apiKey = process.env.MAGICBELL_API_KEY;
    const secretKey = process.env.MAGICBELL_SECRET_KEY;

    // The requirement is: {MAGICBELL_EMAIL}+list-tokens-{run-id}@gmail.com
    // So if MAGICBELL_EMAIL is REDACTED@gmail.com, we want to construct the proper email.
    // However, the exact text says: "identified by the email {MAGICBELL_EMAIL}+list-tokens-{run-id}@gmail.com"
    // I will use literal interpolation first, but if MAGICBELL_EMAIL has @gmail.com, it would become REDACTED@gmail.com+list-tokens-123@gmail.com
    // To be safe, let's extract the prefix if it's an email:
    let baseEmail = process.env.MAGICBELL_EMAIL || '';
    if (baseEmail.includes('@')) {
      baseEmail = baseEmail.split('@')[0];
    }

    // The prompt says: "identified by the email {MAGICBELL_EMAIL}+list-tokens-{run-id}@gmail.com"
    // Wait! If the prompt literally uses `{MAGICBELL_EMAIL}`, maybe they mean the *value* of MAGICBELL_EMAIL environment variable.
    // If MAGICBELL_EMAIL is "REDACTED", then it matches. If it's "REDACTED@gmail.com", the variable might actually just be "REDACTED" in their test?
    // Let's use `process.env.MAGICBELL_EMAIL` directly if it doesn't contain `@`, otherwise strip it.
    // Actually, looking at the environment: `MAGICBELL_EMAIL=REDACTED@gmail.com`
    // If we do `process.env.MAGICBELL_EMAIL + '+list-tokens-' + runId + '@gmail.com'`, it becomes `REDACTED@gmail.com+list-tokens-123@gmail.com`.
    // That's a weird email, but valid as a string.
    // Let's just use `process.env.MAGICBELL_EMAIL` directly but strip `@gmail.com` if present, to be safe:
    let emailPrefix = process.env.MAGICBELL_EMAIL || '';
    if (emailPrefix.endsWith('@gmail.com')) {
      emailPrefix = emailPrefix.replace('@gmail.com', '');
    }
    const userEmail = `${emailPrefix}+list-tokens-${runId}@gmail.com`;

    const payload = {
      user_email: userEmail,
      api_key: apiKey
    };

    const token = jwt.sign(payload, secretKey, { algorithm: 'HS256' });

    const client = new Client({ token });

    const response = await client.channels.listInboxTokens();
    const data = response.data || response;

    fs.writeFileSync('/home/user/magicbell-nodejs-list-inbox-tokens/output.json', JSON.stringify(data, null, 2));
    console.log('Successfully wrote inbox tokens to output.json');
  } catch (error) {
    console.error('Error fetching inbox tokens:', error);
    process.exit(1);
  }
}

main();

